import React, { useState, useEffect } from "react";
import "./RepositoriesSearchBar.css";

export default function RepositoriesSearchBar({ repos, onSearchChange }) {
  const [query, setQuery] = useState("");
  const [showFilters, setShowFilters] = useState(false);
  const [activeFilters, setActiveFilters] = useState({
    language: [],
    stars: [],
    forks: [],
    updated: [],
  });
  const [suggestions, setSuggestions] = useState([]);

  const [availableFilters, setAvailableFilters] = useState({
    language: [],
    stars: [],
    forks: [],
    updated: [],
  });

  /* ------------------- CREA FILTRI DINAMICI ------------------- */
  useEffect(() => {
    const languages = Array.from(
      new Set(repos.flatMap(r => r.languages))
    ).sort();

    const stars = Array.from(
      new Set(
        repos.map(r =>
          r.stars > 100
            ? ">100"
            : r.stars > 50
            ? ">50"
            : r.stars > 10
            ? ">10"
            : ">0"
        )
      )
    ).sort();

    const forks = Array.from(
      new Set(
        repos.map(r =>
          r.forks > 50 ? ">50" : r.forks > 10 ? ">10" : ">0"
        )
      )
    ).sort();

    const updated = Array.from(
      new Set(
        repos.map(r => {
          const diff = (new Date() - new Date(r.lastUpdate)) / (1000 * 3600 * 24);
          return diff < 7 ? "last week" : diff < 30 ? "last month" : "older";
        })
      )
    );

    setAvailableFilters({ language: languages, stars, forks, updated });
  }, [repos]);

  /* ---------------- AUTOCOMPLETE ---------------- */
  const handleChange = (value) => {
    setQuery(value);

    if (value.length > 1) {
      const matches = repos
        .filter(r => r.name.toLowerCase().includes(value.toLowerCase()))
        .slice(0, 5);

      setSuggestions(matches);
    } else {
      setSuggestions([]);
    }

    onSearchChange(value, activeFilters);
  };

  /* ---------------- TOGGLE FILTRO ---------------- */
  const toggleFilter = (type, value) => {
    let updated = { ...activeFilters };
    if (updated[type].includes(value)) {
      updated[type] = updated[type].filter(v => v !== value);
    } else {
      updated[type].push(value);
    }
    setActiveFilters(updated);
    onSearchChange(query, updated);
  };

  return (
    <div className="repositories-searchbar-container">

      {/* INPUT + ICONA FILTRI */}
      <div className="repositories-searchbar-main">
        <input
          type="text"
          placeholder="Cerca repository..."
          value={query}
          onChange={(e) => handleChange(e.target.value)}
        />
        <button className="filter-btn" onClick={() => setShowFilters(!showFilters)}>
          ⚙️
        </button>
      </div>

      {/* AUTOCOMPLETE */}
      {suggestions.length > 0 && (
        <div className="autocomplete-box">
          {suggestions.map(repo => (
            <div
              key={repo.id}
              onClick={() => {
                setQuery(repo.name);
                setSuggestions([]);
                onSearchChange(repo.name, activeFilters);
              }}
            >
              {repo.name}
            </div>
          ))}
        </div>
      )}

      {/* FILTRI ATTIVI */}
      <div className="active-filters">
        {Object.keys(activeFilters).map(type =>
          activeFilters[type].map(f => (
            <span key={`${type}-${f}`} className="filter-pill">{f}</span>
          ))
        )}
      </div>

      {/* FILTRI DINAMICI ESPANDIBILI */}
      {showFilters && (
        <div className="filters-panel">
          {Object.keys(availableFilters).map(type => (
            <div className="filter-group" key={type}>
              <span>{type.charAt(0).toUpperCase() + type.slice(1)}:</span>
              {availableFilters[type].map(f => (
                <button
                  key={f}
                  className={activeFilters[type].includes(f) ? "active" : ""}
                  onClick={() => toggleFilter(type, f)}
                >
                  {f}
                </button>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
